import React, { useEffect, useState } from "react";
import axios from "axios";

const NotesCards = () => {

    const userId = localStorage.getItem("userId");

    const categoryColors = {
        Work: "bg-purple-500",
        Personal: "bg-pink-500",
        Study: "bg-yellow-400 text-black",
        Health: "bg-green-500",
        Finance: "bg-indigo-500",
        All: "bg-gray-400"
    };

    const [todos, setTodos] = useState([]);

    // 🔥 FETCH TODOS FROM BACKEND
    const fetchTodos = async () => {
        try {
            const res = await axios.get(
                `http://localhost:5001/api/todos?userId=${userId}`
            );
            setTodos(res.data);
        } catch (err) {
            console.error("FETCH ERROR 👉", err);
        }
    };

    useEffect(() => {
        if (userId) {
            fetchTodos();
        }
    }, [userId]);

    // 🔥 TOGGLE COMPLETE (BACKEND CALL)
    const handleToggle = async (id) => {
        try {
            await axios.put(
                `http://localhost:5001/api/todos/toggle/${id}`
            );

            // 🔄 refresh list
            fetchTodos();

        } catch (err) {
            console.error("TOGGLE ERROR 👉", err);
        }
    };

    return (
        <div className="min-h-screen bg-[rgb(35,46,88)] p-6">

            {/* 🔥 Cards Grid */}
            <div className="grid sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-5">

                {todos.length === 0 ? (
                    <p className="text-white text-center col-span-full">
                        No Tasks Found 😢
                    </p>
                ) : (
                    todos.map((todo) => (
                        <div
                            key={todo._id}
                            className="bg-white/10 backdrop-blur-lg border border-white/20 rounded-xl p-4 text-white shadow-md hover:scale-105 transition flex flex-col justify-between h-[220px]"
                        >

                            {/* Category */}
                            <div className="flex">
                                <span
                                    className={`text-xs px-2 py-1 rounded-full ${
                                        categoryColors[todo.category] || "bg-gray-500"
                                    }`}
                                >
                                    {todo.category || "No Category"}
                                </span>
                            </div>

                            {/* Title + Desc */}
                            <div>
                                <h3 className="text-lg font-semibold truncate">
                                    {todo.title}
                                </h3>

                                <p className="text-sm text-white/70 mt-2 line-clamp-3">
                                    {todo.description || "No Description"}
                                </p>
                            </div>

                            {/* Button */}
                            <div className="mt-4">

                                {todo.completed ? (
                                    <button
                                        disabled
                                        className="w-full py-2 bg-green-500 text-white rounded-lg text-sm cursor-not-allowed opacity-80"
                                    >
                                        Completed
                                    </button>
                                ) : (
                                    <button
                                        onClick={() => handleToggle(todo._id)}
                                        className="w-full py-2 bg-white text-black rounded-lg text-sm hover:bg-white/90 transition"
                                    >
                                        Mark as Completed
                                    </button>
                                )}

                            </div>

                        </div>
                    ))
                )}

            </div>

        </div>
    );
};

export default NotesCards;
